class GraphRetractRequest(BaseModel):
    """
    Retract specific edges and/or every edge touching given entities. Graph facts
    are append-only; a retraction does not erase events but appends a retracting
    event that supersedes the matched current edges, so they drop out of
    current-state reads (and re-appear in an `as_of` read before the retraction).
    This is the surgical alternative to the whole-graph reset for fixing a
    wrongly-added fact — e.g. an auto-extracted entity that turned out to be noise.
    """

    edges: Annotated[
        list[RetractEdgeInput] | None,
        Field(
            description='Specific edges to retract, matched against current edges by\n(source, relation, target).'
        ),
    ] = None
    entities: Annotated[
        list[NamedEntityInput] | None,
        Field(
            description='Entities whose every current edge (as source or target) is retracted —\neffectively tombstoning the entity from current-state reads. The entity\nrecord itself is retained (append-only) and stays visible in `as_of` reads.'
        ),
    ] = None
    purge_entity_properties: Annotated[
        bool | None,
        Field(
            description='Also clear every stored scalar property (`text`, `acl`, …) of each entity\nin `entities`, so the entity has **no current presence** and fully leaves\nsearch AND SPARQL in this one call — the "delete this record" primitive.\nWithout it, `retract` tombstones edges only; a property-carrying entity\n(e.g. a content chunk with an `acl`) stays searchable and ACL-filterable\nbecause presence is `live-edge OR non-empty properties`. Append-only: the\nrecords survive in `as_of` reads; only the current property set is cleared\n(a later `commit` can repopulate it). No-op for `edges`-only requests.'
        ),
    ] = None


